Based on the reference materials and detailed specifications, here's the complete implementation of the `delete_inactive_users` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result.is_ok()) {
    return 1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result.is_ok()) {
    return 1; // Transaction begin failed
  }

  try {
    // 3. Create delete operation with where condition
    auto delete_op = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");

    // 4. Execute the delete operation
    auto delete_result = delete_op(conn);
    if (!delete_result.is_ok()) {
      // Rollback on delete failure
      conn->rollback();
      return 1; // Delete operation failed
    }

    // 5. Commit the transaction
    auto commit_result = conn->commit();
    if (!commit_result.is_ok()) {
      conn->rollback();
      return 1; // Commit failed
    }

    // 6. Return commit result (0 for success)
    return 0;

  } catch (const std::exception& e) {
    // Rollback on any exception
    conn->rollback();
    return 1; // Operation failed with exception
  }
}

} // namespace delete_inactive_users
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` as specified
2. **Transaction Safety**: Wraps the entire operation in a transaction with proper rollback on failures
3. **Delete Operation**: Uses `sqlgen::delete_from<User>` with pipe operator `|` to chain operations
4. **Where Condition**: Applies `"last_login"_c < "2025-01-01"` using column literal and comparison operator
5. **Error Handling**: Comprehensive error handling with proper transaction rollback
6. **Return Value**: Returns 0 for success (commit result), 1 for any failure

The implementation follows all the assessment objectives and uses the sqlgen library functions and patterns as shown in the reference materials.

