      {2, 3, Timestamp("2023-01-02 11:00:00")}, // Bob - Charlie
      {1, 4, Timestamp("2023-01-03 12:00:00")}  // Alice - David
  };

  auto connections = analyze_social_network_impl(users, friendships);

