bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;

  // Begin transaction
  auto txn_res = begin_transaction(conn_res.value());
  if (!txn_res) return false;
  auto txn = txn_res.value();

  // Define column references for the Product table
  auto product_id_c = "product_id"_c;
  auto stock_c = "stock"_c;

  // Iterate through each product shipment and update stock
  for (const auto& [product_id, quantity] : received) {
    // Create UPDATE statement using sqlgen's type-safe API
    auto update_stmt = update<Product>(
      stock_c.set(stock_c + quantity)  // Set stock = stock + quantity
    ) | where(product_id_c == product_id);  // Where condition

    // Execute the update statement within the transaction
    auto exec_res = exec(txn, to_sql(update_stmt));
    if (!exec_res) {
      // If any update fails, rollback the transaction
      rollback(txn);
